#include <iostream>
#include <string>
using namespace std;

int lengthAfterTransformation(string s, int t, vector<int>& nums) {
    int result = 0;
    for (int i = 0; i < s.length(); i++) {
        int index = s[i] - 'a' + nums[i];
        result = (result + (index >= 26) ? 0 : index);
    }
    return result;
}
